void reflex_code_HTTP_Reflex_Scanner_INITIAL(reflex::Matcher& m)
{
  int c = 0;
  m.FSM_INIT(c);

S0:
  m.FSM_FIND();
  c = m.FSM_CHAR();
  if (c == 'P') goto S13;
  if (c == 'N') goto S19;
  if (c == 'M') goto S16;
  if (c == 'H') goto S6;
  if (c == 'G') goto S10;
  if (0 <= c) goto S22;
  return m.FSM_HALT(c);

S6:
  m.FSM_TAKE(3);
  c = m.FSM_CHAR();
  if (c == 'T') goto S24;
  if (c == 'E') goto S26;
  return m.FSM_HALT(c);

S10:
  m.FSM_TAKE(3);
  c = m.FSM_CHAR();
  if (c == 'E') goto S28;
  return m.FSM_HALT(c);

S13:
  m.FSM_TAKE(3);
  c = m.FSM_CHAR();
  if (c == 'O') goto S30;
  return m.FSM_HALT(c);

S16:
  m.FSM_TAKE(3);
  c = m.FSM_CHAR();
  if (c == '-') goto S32;
  return m.FSM_HALT(c);

S19:
  m.FSM_TAKE(3);
  c = m.FSM_CHAR();
  if (c == 'O') goto S34;
  return m.FSM_HALT(c);

S22:
  m.FSM_TAKE(3);
  return m.FSM_HALT();

S24:
  c = m.FSM_CHAR();
  if (c == 'T') goto S36;
  return m.FSM_HALT(c);

S26:
  c = m.FSM_CHAR();
  if (c == 'A') goto S38;
  return m.FSM_HALT(c);

S28:
  c = m.FSM_CHAR();
  if (c == 'T') goto S40;
  return m.FSM_HALT(c);

S30:
  c = m.FSM_CHAR();
  if (c == 'S') goto S42;
  return m.FSM_HALT(c);

S32:
  c = m.FSM_CHAR();
  if (c == 'S') goto S44;
  return m.FSM_HALT(c);

S34:
  c = m.FSM_CHAR();
  if (c == 'T') goto S46;
  return m.FSM_HALT(c);

S36:
  c = m.FSM_CHAR();
  if (c == 'P') goto S48;
  return m.FSM_HALT(c);

S38:
  c = m.FSM_CHAR();
  if (c == 'D') goto S40;
  return m.FSM_HALT(c);

S40:
  m.FSM_TAKE(2);
  return m.FSM_HALT();

S42:
  c = m.FSM_CHAR();
  if (c == 'T') goto S40;
  return m.FSM_HALT(c);

S44:
  c = m.FSM_CHAR();
  if (c == 'E') goto S50;
  return m.FSM_HALT(c);

S46:
  c = m.FSM_CHAR();
  if (c == 'I') goto S52;
  return m.FSM_HALT(c);

S48:
  c = m.FSM_CHAR();
  if (c == '/') goto S54;
  return m.FSM_HALT(c);

S50:
  c = m.FSM_CHAR();
  if (c == 'A') goto S56;
  return m.FSM_HALT(c);

S52:
  c = m.FSM_CHAR();
  if (c == 'F') goto S58;
  return m.FSM_HALT(c);

S54:
  c = m.FSM_CHAR();
  if ('0' <= c && c <= '9') goto S60;
  return m.FSM_HALT(c);

S56:
  c = m.FSM_CHAR();
  if (c == 'R') goto S62;
  return m.FSM_HALT(c);

S58:
  c = m.FSM_CHAR();
  if (c == 'Y') goto S40;
  return m.FSM_HALT(c);

S60:
  c = m.FSM_CHAR();
  if (c == '.') goto S64;
  return m.FSM_HALT(c);

S62:
  c = m.FSM_CHAR();
  if (c == 'C') goto S66;
  return m.FSM_HALT(c);

S64:
  c = m.FSM_CHAR();
  if ('0' <= c && c <= '9') goto S68;
  return m.FSM_HALT(c);

S66:
  c = m.FSM_CHAR();
  if (c == 'H') goto S40;
  return m.FSM_HALT(c);

S68:
  m.FSM_TAKE(1);
  return m.FSM_HALT();
}

